def run_samc2_variants_for_ablation(y: np.ndarray, alpha: float = 0.1, variant: str = "full"):
    T = len(y)
    fore = SeasonalNaiveEWMA(season_lag=24, bias_lag=169)
    cfg = SAMC2Config(alpha=alpha)
    ctrl = MultiResController(cfg)
    agg = SleepingExpertsAggregator(cfg, num_scales=len(cfg.scales))
    cs = DyadicCSLayer(alpha)

    # variant toggles
    use_cs = True
    use_efficiency = True
    use_barrier_beta = True
    uniform_avg = False

    if variant == "no_cs":
        use_cs = False
    elif variant == "uniform_avg":
        uniform_avg = True
    elif variant == "no_efficiency":
        use_efficiency = False
    elif variant == "no_barrier":
        use_barrier_beta = False
    elif variant == "full":
        pass
    else:
        pass

    # Storage
    errs = np.zeros(T, dtype=int)
    qs = np.zeros(T, dtype=float)
    weights = np.zeros((T, len(cfg.scales)), dtype=float)
    per_expert_loss = np.zeros((T, len(cfg.scales)), dtype=float)

    yhat = 0.0
    scores_recent = []

    for t in range(T):
        yhat = fore.step(t, y[t - 1] if t > 0 else y[0])
        if t == 0:
            props, qmax = ctrl.update_after_observation(0, 0.0)
            cs_press = cs.pressures_for_scales(t, ctrl.scales.numpy()) if use_cs else torch.zeros_like(props)
            if uniform_avg:
                w = torch.full_like(props, 1.0 / len(props))
                q = float(torch.dot(w, props))
            else:
                if not use_efficiency:
                    # Temporarily change lam/beta
                    old_lam, old_beta = agg.cfg.lam, agg.cfg.barrier_beta
                    agg.cfg.lam = 1.0
                    agg.cfg.barrier_beta = 0.0 if not use_barrier_beta else old_beta
                    q, loss = agg.step(props, 0, qmax, cs_press if use_cs else None)
                    agg.cfg.lam = old_lam
                    agg.cfg.barrier_beta = old_beta
                else:
                    if not use_barrier_beta:
                        old_beta = agg.cfg.barrier_beta; agg.cfg.barrier_beta = 0.0
                        q, loss = agg.step(props, 0, qmax, cs_press if use_cs else None)
                        agg.cfg.barrier_beta = old_beta
                    else:
                        q, loss = agg.step(props, 0, qmax, cs_press if use_cs else None)
            qs[t] = q
            weights[t, :] = agg.w.detach().cpu().numpy() if not uniform_avg else (np.ones(len(cfg.scales)) / len(cfg.scales))
            per_expert_loss[t, :] = agg.last_losses.detach().cpu().numpy() if not uniform_avg else np.zeros(len(cfg.scales))
            continue

        score = abs(y[t] - yhat)
        err = int(abs(y[t] - yhat) > qs[t - 1])
        errs[t] = err
        props, qmax = ctrl.update_after_observation(err, score)
        if use_cs:
            cs.update(t, err, alpha)
            cs_press = cs.pressures_for_scales(t, ctrl.scales.numpy())
        else:
            cs_press = torch.zeros_like(props)
        scores_recent.append(score)
        if len(scores_recent) > 1024:
            scores_recent.pop(0)
        agg.update_scale(scores_recent)

        if uniform_avg:
            w = torch.full_like(props, 1.0 / len(props))
            q = float(torch.dot(w, props))
            last_losses = torch.zeros_like(props)
        else:
            if not use_efficiency:
                old_lam, old_beta = agg.cfg.lam, agg.cfg.barrier_beta
                agg.cfg.lam = 1.0
                agg.cfg.barrier_beta = 0.0 if not use_barrier_beta else old_beta
                q, last_losses = agg.step(props, err, qmax, cs_press if use_cs else None)
                agg.cfg.lam = old_lam
                agg.cfg.barrier_beta = old_beta
            else:
                if not use_barrier_beta:
                    old_beta = agg.cfg.barrier_beta; agg.cfg.barrier_beta = 0.0
                    q, last_losses = agg.step(props, err, qmax, cs_press if use_cs else None)
                    agg.cfg.barrier_beta = old_beta
                else:
                    q, last_losses = agg.step(props, err, qmax, cs_press if use_cs else None)

        qs[t] = q
        weights[t, :] = agg.w.detach().cpu().numpy() if not uniform_avg else (np.ones(len(cfg.scales)) / len(cfg.scales))
        per_expert_loss[t, :] = last_losses.detach().cpu().numpy() if not uniform_avg else np.zeros(len(cfg.scales))

    return errs, qs, weights, per_expert_loss, cfg.scales


def experiment3_ablation(T=60_000, seed=7, alpha=0.1, plot_prefix="ablation"):
    print("[Exp3] Ablations and strongly adaptive regret starting...")
    y, segments, W_star_seq = generate_regime_carousel_ex3(T=T, seed=seed)

    variants = ["full", "no_cs", "uniform_avg", "no_efficiency", "no_barrier"]
    results = {}
    for v in variants:
        print(f"  - Running variant: {v}")
        errs, qs, weights, per_expert_loss, scales = run_samc2_variants_for_ablation(y, alpha=alpha, variant=v)
        results[v] = {
            "err": errs,
            "q": qs,
            "w": weights,
            "loss_s": per_expert_loss,
            "scales": np.array(scales, dtype=float)
        }

    # Compute strongly adaptive regret over sliding windows
    Ls = [32, 128, 512, 2048]
    reg_stats = {v: [] for v in variants}
    for v in variants:
        loss_s = results[v]["loss_s"]  # T x S
        # oracle per window: min_s sum loss_s
        for L in Ls:
            if loss_s.shape[0] <= L:
                continue
            sums = np.cumsum(loss_s, axis=0)
            # window sum: sums[t] - sums[t-L]
            reg_list = []
            # method loss (SAMC2 variant): need per-step composite loss; we can use average across experts weighted by weights? Use observed aggregator loss by reconstructing as dot(w, loss_s)
            w = results[v]["w"]
            agg_loss = np.sum(w * loss_s, axis=1)
            agg_sums = np.cumsum(agg_loss)
            for t in range(L, loss_s.shape[0]):
                sum_win = sums[t, :] - sums[t - L, :]
                oracle = float(np.min(sum_win))
                agg_win = float(agg_sums[t] - agg_sums[t - L])
                reg = agg_win - oracle
                reg_list.append(reg / math.sqrt(L))
            reg_stats[v].append((L, np.median(reg_list)))

    # Plot normalized regret
    plt.figure(figsize=(6, 4))
    for v in variants:
        xs = [L for (L, med) in reg_stats[v]]
        ys = [med for (L, med) in reg_stats[v]]
        plt.plot(xs, ys, marker='o', label=v)
    plt.xlabel("Window length L")
    plt.ylabel("Median Reg_I/√L")
    plt.title("Exp3 strongly adaptive regret (median)")
    plt.legend()
    plt.grid(True, alpha=0.3)
    plt.tight_layout()
    plt.savefig("regret_normalized_ablation.pdf", bbox_inches="tight")
    plt.close()

    # Pivot time: compute after each segment when weight on W* exceeds 0.5
    plt.figure(figsize=(6, 4))
    pivot_times = defaultdict(list)
    scale_vals = results["full"]["scales"]  # same across variants
    for v in variants:
        w = results[v]["w"]
        for (a, b, wstar) in W_star_seq:
            # find index of closest scale to wstar
            idx = int(np.argmin(np.abs(scale_vals - wstar)))
            # time to first t in [a,b] s.t. w[t, idx] >= 0.5
            subw = w[a:b+1, idx]
            hit = np.where(subw >= 0.5)[0]
            pt = (int(hit[0]) if hit.size > 0 else (b - a + 1))
            pivot_times[v].append(pt)
        # Plot distribution summary via boxplot metric: median per variant
    medians = [np.median(pivot_times[v]) for v in variants]
    sns.barplot(x=variants, y=medians, color='#4C72B0')
    plt.ylabel("Median pivot time (steps)")
    plt.title("Exp3 pivot time by variant")
    plt.tight_layout()
    plt.savefig("pivot_time_distribution_ablation.pdf", bbox_inches="tight")
    plt.close()

    # Width stability: TV(q) and max |Δq|
    plt.figure(figsize=(6, 4))
    tvs = [total_variation(results[v]["q"]) for v in variants]
    max_dq = [float(np.max(np.abs(np.diff(results[v]["q"])))) if len(results[v]["q"]) > 1 else 0.0 for v in variants]
    x = np.arange(len(variants))
    plt.bar(x - 0.2, tvs, width=0.4, label='TV(q)')
    plt.bar(x + 0.2, max_dq, width=0.4, label='max |Δq|')
    plt.xticks(x, variants)
    plt.ylabel("Stability metrics")
    plt.title("Exp3 width stability by variant")
    plt.legend()
    plt.tight_layout()
    plt.savefig("width_stability_ablation.pdf", bbox_inches="tight")
    plt.close()

    print("[Exp3] Regret, pivot, and stability plots saved: regret_normalized_ablation.pdf, pivot_time_distribution_ablation.pdf, width_stability_ablation.pdf")


